firmware_template.source:
#include "pca9685.h"
#include <Wire.h>
#include <Adafruit_PWMServoDriver.h>
static Adafruit_PWMServoDriver pwm;
void pca9685_setup(){Wire.begin();pwm.begin();pwm.setOscillatorFrequency(27000000);pwm.setPWMFreq(50);Serial.println("[pca9685] OK 16ch");}
void pca9685_set_pwm(uint8_t ch,uint16_t on,uint16_t off){pwm.setPWM(ch,on,off);}
void pca9685_set_servo(uint8_t ch,int a){uint16_t p=map(constrain(a,0,180),0,180,150,600);pwm.setPWM(ch,0,p);}
void pca9685_set_duty(uint8_t ch,float d){pwm.setPWM(ch,0,(uint16_t)(d*4095));}
